if (! function_exists('text_haiku_to_emoji')) {
    function text_haiku_to_emoji($haiku_text, $season_topic = null)
    {
        $lines = explode("\n", trim($haiku_text));
        if (count($lines) < 3) { $lines = preg_split('/[.!?]+/', $haiku_text, 3); }
        if (count($lines) < 3) { return ['error' => 'Haiku must have at least 3 lines', 'text' => $haiku_text]; }

        $seasonMap = [
            'spring' => ['🌸','🌷','🌱','🦋','🐝'],
            'summer' => ['☀️','🌻','🏖️','🍉','🌊'],
            'autumn' => ['🍂','🍁','🌾','🎑','🌰'],
            'winter' => ['❄️','⛄','🌨️','🧣','🕯️'],
            'default' => ['🌿','🌟','💫','🌙','✨'],
        ];

        // Simple season detection
        $season = $season_topic ?? 'default';
        if (!$season_topic || !isset($seasonMap[$season])) {
            $lower = strtolower($haiku_text);
            if (preg_match('/sakura|cherry|bloom|petal|warm|bird/', $lower)) $season = 'spring';
            elseif (preg_match('/sun|beach|ocean|swim|hot|ice/', $lower)) $season = 'summer';
            elseif (preg_match('/leaf|fall|harvest|moon|crisp/', $lower)) $season = 'autumn';
            elseif (preg_match('/snow|cold|frost|ice|bare/', $lower)) $season = 'winter';
            else $season = 'default';
        }
        $emojis = $seasonMap[$season] ?? $seasonMap['default'];

        // Line emoji - choose based on content
        $lineEmojis = [];
        foreach ($lines as $i => $line) {
            $line = trim($line);
            if (empty($line)) continue;
            $wordCount = str_word_count($line);
            $emojiIdx = ($i < count($emojis)) ? $i : ($i % count($emojis));
            $lineEmojis[] = ['line' => $line, 'emoji' => $emojis[$emojiIdx], 'words' => $wordCount];
        }

        // Build visual grid
        $grid = [];
        $header = ['🎋', 'Haiku', '📊'];
        $grid[] = $header;
        foreach ($lineEmojis as $le) {
            $barLen = min($le['words'], 7);
            $bar = str_repeat('🟢', $barLen);
            if ($barLen < 7) $bar .= str_repeat('⬜', 7 - $barLen);
            $grid[] = [$le['emoji'], $le['line'], $bar];
        }

        // Add season footer
        $footer = ['📍', ucfirst($season), $emojis[0] . $emojis[1] . $emojis[2]];
        $grid[] = $footer;

        return [
            'season_detected' => $season,
            'lines' => count($lineEmojis),
            'grid' => $grid,
            'next_step' => "Pass the 'grid' to emoji_art_renderer to render the visual haiku art."
        ];
    }
}
